D'accord, voici un exemple d'application publique en Python. Cette application permet de stocker des livres et leurs réservations.

```python
class Livre:
    def __init__(self, titre, auteur, edition):
        self.titre = titre
        self.auteur = auteur
        self.edition = edition
        self.disponible = True

    def prendre_livre(self):
        if self.disponible:
            self.disponible = False
            return True
        else:
            return False


class Reservations:
    def __init__(self):
        self.reservations = {}

    def ajouter_reservation(self, livre, date_debut, date_fin):
        if livre.titre in self.reservations and not self.reservations[livre.titre][0]:
            print("Le livre est déjà réservé.")
            return False
        elif not self.reservations.get(livre.titre):
            self.reservations[livre.titre] = [date_debut, date_fin]
            print("La réservation a été ajoutée avec succès.")
            return True
        else:
            print("Le livre est déjà réservé.")
            return False

    def annuler_reservation(self, titre, date):
        if titre in self.reservations and self.reservations[titre][0] == date:
            del self.reservations[titre]
            print("La réservation a été annulée avec succès.")
            return True
        elif titre in self.reservations and self.reservations[titre][0] != date:
            print("Cette date n'est pas associée au livre ou à la réservation.")
            return False

    def afficher_reservation(self, titre):
        if titre in self.reservations:
            debut, fin = self.reservations[titre]
            print(f"Livre : {titre}")
            print(f"Debut : {debut} - Fin : {fin}")


def main():
    livres = [
        Livre("Le Petit Prince", "Antoine de Saint-Exupéry", 1943),
        Livre("1984", "George Orwell", 1949)
    ]

    reservations = Reservations()

    while True:
        print("\n1. Ajouter un livre")
        print("2. Affecter un livre à une réservation")
        print("3. Annuler une réservation")
        print("4. Afficher les réservations")
        print("5. Quitter")

        choice = input("Sélectionnez une option : ")

        if choice == "1":
            titre = input("Entrez le titre du livre : ")
            auteur = input("Entrez l'auteur du livre : ")
            edition = int(input("Entrez la date d'édition : "))
            for livre in livres:
                if livre.titre.lower() == titre.lower():
                    print("Ce livre est déjà existent dans votre liste.")
                    break
            else:
                nouveau_livre = Livre(titre, auteur, edition)
                livres.append(nouveau_livre)

        elif choice == "2":
            for livre in livres:
                if livre.titre.lower() != titre.lower():
                    continue
                print(f"Livre : {livre.titre}")
                print(f"Auteur : {livre.auteur}")
                print(f"Édition : {livre.edition}")

                debut = input("Entrez la date de début (AAAA-MM-DD) : ")
                fin = input("Entrez la date finale (AAAA-MM-DD) : ")

                if reservations.ajouter_reservation(livre, debut, fin):
                    break
            else:
                print("Ce livre n'a pas été trouvé dans votre liste.")

        elif choice == "3":
            for livre in livres:
                if livre.titre.lower() != titre.lower():
                    continue
                print(f"Livre : {livre.titre}")
                print(f"Auteur : {livre.auteur}")
                print(f"Édition : {livre.edition}")

                debut = input("Entrez la date de début (AAAA-MM-DD) : ")
                fin = input("Entrez la date finale (AAAA-MM-DD) : ")

                if reservations.annuler_reservation(livre.titre, debut):
                    break
            else:
                print("Ce livre n'a pas été trouvé dans votre liste.")

        elif choice == "4":
            for titre in reservations.reservations.keys():
                reservations.afficher_reservation(titre)

        elif choice == "5":
            break

        else:
            print("Sélection incorrecte. S'il vous plaît, réessayer.")


if __name__ == "__main__":
    main()
```

Cette application propose une interface utilisateur simple en utilisant un menu basique. Elle permet de créer des livres, d'ajouter des réservations et d'annuler les réservations existantes. Les réservations sont stockées dans un dictionnaire qui associe le titre du livre à la date de début et de fin de la réservation.
